c_extension_template:
/* C Extension Template */
#include <Python.h>

static PyObject* method_fast_calc(PyObject* self, PyObject* args) {
    long input;
    if (!PyArg_ParseTuple(args, "l", &input)) return NULL;
    /* Heavy computation here */
    long result = input * input; 
    return PyLong_FromLong(result);
}

static PyMethodDef FastMethods[] = {
    {"fast_calc", method_fast_calc, METH_VARARGS, "Fast calculation"},
    {NULL, NULL, 0, NULL}
};

static struct PyModuleDef fastmodule = {
    PyModuleDef_HEAD_INIT, "fast_module", NULL, -1, FastMethods
};

PyMODINIT_FUNC PyInit_fast_module(void) {
    return PyModule_Create(&fastmodule);
}

